class Solution {
    // Function to find the number of connected components in the graph
    public int findConnectedComponents(int n, int[][] edges) {
        // Initialize adjacency list and visited array
        ArrayList<Integer>[] adjList = new ArrayList[n + 1];
        boolean[] visited = new boolean[n + 1];

        // Initialize adjacency list and visited array
        for (int i = 1; i <= n; i++) {
            adjList[i] = new ArrayList<>(); // Create an empty list for each node
            visited[i] = false; // Mark all nodes as not visited
        }

        // Build the adjacency list from the edges
        for (int[] edge : edges) {
            int u = edge[0];
            int v = edge[1];
            adjList[u].add(v); // Add edge from u to v
            adjList[v].add(u); // Add edge from v to u (undirected graph)
        }

        // Count connected components
        int components = 0;
        for (int i = 1; i <= n; i++) {
            if (!visited[i]) { // If the node has not been visited
                components++; // Found a new connected component
                dfs(i, adjList, visited); // Perform DFS to mark all nodes in this component
            }
        }

        return components; // Return the number of connected components
    }

    // Function to perform DFS and mark visited nodes
    private void dfs(int node, ArrayList<Integer>[] adjList, boolean[] visited) {
        visited[node] = true; // Mark the current node as visited
        for (int v : adjList[node]) { // Iterate over all neighbors of the current node
            if (!visited[v]) { // If a neighbor has not been visited
                dfs(v, adjList, visited); // Recursively perform DFS on the neighbor
            }
        }
    }
}

