// Function to find the number of connected components in the graph
function findConnectedComponents(n, edges) {
    // Initialize adjacency list and visited array
    let adjList = Array.from({ length: n + 1 }, () => []);
    let visited = Array.from({ length: n + 1 }, () => false);

    // Build the graph by populating the adjacency list
    for (const [u, v] of edges) {
        adjList[u].push(v); // Add edge from u to v
        adjList[v].push(u); // Add edge from v to u (undirected graph)
    }

    // Depth-First Search (DFS) function
    function dfs(startNode) {
        const stack = [startNode];
        while (stack.length > 0) {
            const node = stack.pop(); // Get the current node
            if (!visited[node]) {
                visited[node] = true; // Mark the node as visited
                // Push all unvisited neighbors onto the stack
                for (const neighbor of adjList[node]) {
                    if (!visited[neighbor]) {
                        stack.push(neighbor);
                    }
                }
            }
        }
    }

    // Find the number of connected components
    let groupOfConnectedPlanets = 0;
    for (let i = 1; i <= n; i++) {
        if (!visited[i]) { // If the node is not visited, it's a new component
            groupOfConnectedPlanets++;
            dfs(i); // Perform DFS to visit all nodes in this component
        }
    }

    return groupOfConnectedPlanets; // Return the number of connected components
}
